         if (max == 0) return new ReadOnlyCollection<int>([]);
         int[] histogram = new int[max + 1];
         for (int i = 0; i < _wordLengths.Count; i++)
             histogram[_wordLengths[i]]++;
         return new ReadOnlyCollection<int>(histogram);
     }

